<!doctype html><html><body style="font-family:Arial,sans-serif;color:#172033"><h2>Payment received</h2><p>Thank you. We recorded your payment for invoice <strong>{{ $invoice->invoice_number }}</strong>.</p><table cellpadding="7" cellspacing="0" style="border-collapse:collapse"><tr><td>Amount</td><td><strong>{{ $payment->currency }} {{ number_format($payment->amount,2) }}</strong></td></tr><tr><td>Reference</td><td>{{ $payment->reference }}</td></tr><tr><td>Payment date</td><td>{{ optional($payment->paid_at)->format('Y-m-d') }}</td></tr><tr><td>Remaining balance</td><td>{{ $invoice->currency }} {{ number_format($invoice->balance,2) }}</td></tr></table></body></html>
